const { withInfoPlist } = require('expo/config-plugins');

const isTV = process.env.EXPO_TV === '1' || process.env.EXPO_TV === 'true';

/**
 * tvOS builds generated by `@react-native-tvos/config-tv` inherit Expo's shared
 * iOS Info.plist template, which leaves `LSRequiresIPhoneOS = true` in place.
 * App Store Connect then validates the Apple TV binary as an iOS app and rejects
 * it (ITMS-90508 / 90545 / 90713 / 90039). Strip the iOS-only marker keys so the
 * bundle is validated as tvOS. No-op unless building for TV (EXPO_TV=1).
 */
module.exports = function withTvInfoPlistCleanup(config) {
  if (!isTV) return config;

  return withInfoPlist(config, (cfg) => {
    delete cfg.modResults.LSRequiresIPhoneOS;
    delete cfg.modResults.LSMinimumSystemVersion;
    return cfg;
  });
};
